mapper.select:
SELECT ORDER_COUNT
  FROM T_IPO_PO_ORDER TIPO
 WHERE TIPO.PRODUCT_CODE      = #{bbProductCode}
   AND TIPO.PRESENTATION_FROM = TO_NUMBER(#{bbPresentationFrom})
   AND TIPO.BUTEN_CODE        = #{bbBranchCode}
   AND TIPO.ACCOUNT_NUMBER    = TO_NUMBER(#{bbAccountNumber})

	SELECT 1 FROM T_IPO_PO_ORDER
    WHERE PRODUCT_CODE                                  = #{param.bbProductCodeH}
      AND PRESENTATION_FROM                             = TO_NUMBER(#{param.bbPresentationFromH})
      AND BUTEN_CODE                                    = #{param.bbBranchCodeH}
      AND ACCOUNT_NUMBER                                = TO_NUMBER(#{param.bbAccountNumberH})
      AND TO_CHAR(UPDATE_TIME, 'yyyy/MM/dd hh24:mi:ss') = #{param.updateTimeH}
